mapper.select:
select count(*) from departments d where d.dept_seq = #{dept_seq}
	and d.parent_dept_seq = (
		select dept_seq from departments where dept_code = 'CEO'
	)

mapper.update:
update departments 
	set dept_name = #{dept_name} ,
		dept_code = #{dept_code} ,
		auth_group = #{auth_group},
		parent_dept_seq = #{parent_dept_seq}
where dept_seq = #{dept_seq}

mapper.select:
select q.*, u1.name as user_name, u2.name as admin_name from ai_unanswered_questions q left join users u1 on q.users_id = u1.id left join users u2 on q.users_handle_id = u2.id
q.dept_seq = #{dept_seq}
order by q.created_at

mapper.update:
update ai_unanswered_questions set handle_answer = #{handle_answer} , 
users_handle_id = #{users_handle_id}, status = 'ANSWERED', answer_at = sysdate
where question_seq = #{question_seq}

update ai_unanswered_questions set handle_answer = null , 
users_handle_id = null, status = 'PENDING', answer_at = null
where question_seq = #{question_seq}
